#include <bits/stdc++.h>
using namespace std;
#define int long long
int n,c[4],d[4];
vector<int> dp(100005);
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	for(int i=0; i<4; i++) {
		cin>>c[i];
	}
	dp[0]=1;
	for (int i=0; i<4; i++) {
		for (int j=c[i]; j<100005; j++) {
			dp[j]+=dp[j-c[i]];
		}
	}
	cin>>n;
	while(n--) {
		for(int i=0; i<4; i++) {
			cin>>d[i];
		}
		int s,ans=0;
		cin>>s;
		for (int i=0; i<16; i++) {
			int cs=s,cnt=0;
			for(int j=0; j<4; j++) {
				if ((i>>j)&1) {
					cnt++;
					cs-=(d[j]+1)*c[j];
				}
			}
			if(cs>=0) {
				if(cnt&1) {
					ans-=dp[cs];
				} else {
					ans+=dp[cs];
				}
			}
		}
		cout<<ans<<"\n";
	}
	return 0;
}
